package com.aadil.jobtracker.security;import com.aadil.jobtracker.responses.AuthenticationResponse;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.PostMapping;import org.springframework.web.bind.annotation.RequestBody;import org.springframework.web.bind.annotation.RequestMapping;import org.springframework.web.bind.annotation.RestController;@RestController@RequestMapping("/api/auth")public class AuthenticationController {    private final AuthenticationService authenticationService;    public AuthenticationController(AuthenticationService authenticationService) {        this.authenticationService = authenticationService;    }    @PostMapping ("/register")    public ResponseEntity<?> register (@RequestBody RequestRegisterDTO register){        authenticationService.register(register);        return ResponseEntity.ok("User registered Successfully");    }    @PostMapping ("/login")    public ResponseEntity<AuthenticationResponse> login (@RequestBody LoginRequestDTO login){        String token  = authenticationService.login(login);        System.out.println("EMAIL: "+login.getEmail());        System.out.println("PASSWORD: "+login.getPassword());        return ResponseEntity.ok(new AuthenticationResponse(token));    }}